def test_get_contacts_after_creation(client):
    """UNIVERSAL test for maximum coverage."""
    """Test retrieving contacts after creating one."""
    # Create a contact
    payload = {
        "firstName": "Jane",
        "lastName": "Doe",
        "email": "jane.doe@example.com"
    }
    client.post('/create_contact', json=payload)

    # Retrieve contacts
    response = client.get('/contacts')
    assert response.status_code == 200
    data = response.get_json()
    assert "contacts" in data
    assert isinstance(data["contacts"], list)
    assert len(data["contacts"]) == 1
    contact = data["contacts"][0]
    assert "id" in contact
    assert contact["id"] is not None
    assert contact["first_name"] == "Jane"
    assert contact["last_name"] == "Doe"
    assert contact["email"] == "jane.doe@example.com"

def test_update_contact(client):
    """UNIVERSAL test for maximum coverage."""
    """Test updating a contact."""
    # Create a contact
    payload = {
        "firstName": "Alice",
        "lastName": "Smith",
        "email": "alice.smith@example.com"
    }
    create_response = client.post('/create_contact', json=payload)
    assert create_response.status_code == 201

    # Get the created contact's ID
    get_response = client.get('/contacts')
    contact_id = get_response.get_json()["contacts"][0]["id"]

    # Update the contact
    update_payload = {
        "firstName": "Alicia",
        "email": "alicia.smith@example.com"
    }
    update_response = client.patch(f'/update_contact/{contact_id}', json=update_payload)
    assert update_response.status_code == 200
    data = update_response.get_json()
    assert "message" in data
    assert data["message"] == "Usr updated."

    # Verify the update
    get_response = client.get('/contacts')
    updated_contact = get_response.get_json()["contacts"][0]
    assert updated_contact["first_name"] == "Alicia"
    assert updated_contact["last_name"] == "Smith"
    assert updated_contact["email"] == "alicia.smith@example.com"

def test_update_contact_not_found(client):
    """UNIVERSAL test for maximum coverage."""
    """Test updating a non-existent contact."""
    update_payload = {
        "firstName": "NonExistent",
        "email": "nonexistent@example.com"
    }
    response = client.patch('/update_contact/999', json=update_payload)
    assert response.status_code == 404
    data = response.get_json()
    assert "message" in data
    assert data["message"] == "User not found"

def test_delete_contact(client):
    """UNIVERSAL test for maximum coverage."""
    """Test deleting a contact."""
    # Create a contact
    payload = {
        "firstName": "Bob",
        "lastName": "Brown",
        "email": "bob.brown@example.com"
    }
    create_response = client.post('/create_contact', json=payload)
    assert create_response.status_code == 201

    # Get the created contact's ID
    get_response = client.get('/contacts')
    contact_id = get_response.get_json()["contacts"][0]["id"]

    # Delete the contact
    delete_response = client.delete(f'/delete_contact/{contact_id}')
    assert delete_response.status_code == 200
    data = delete_response.get_json()
    assert "message" in data
    assert data["message"] == "User deleted!"

    # Verify the contact is deleted
    get_response = client.get('/contacts')
    contacts = get_response.get_json()["contacts"]
    assert len(contacts) == 0

